import os
import boto3
from botocore.exceptions import NoCredentialsError
from PIL import Image
from io import BytesIO
from selenium import webdriver
from selenium.webdriver.chrome.options import Options
from selenium.webdriver.common.by import By
from urllib.parse import urlparse

# AWS Config
AWS_ACCESS_KEY_ID = 'YOUR_AWS_ACCESS_KEY_ID'
AWS_SECRET_ACCESS_KEY = 'YOUR_AWS_SECRET_ACCESS_KEY'

# S3 Bucket Name
BUCKET_NAME = 'your-bucket-name'

# Chrome Driver Path
CHROME_DRIVER_PATH = '/path/to/chromedriver'

# Allowed Destinations (Social Media Platforms)
ALLOWED_DESTINATIONS = ['facebook', 'twitter', 'linkedin']

def is_allowed_destination(url):
    parsed_url = urlparse(url)
    return parsed_url.netloc in ALLOWED_DESTINATIONS

def get_screenshot(url, width=800, height=600):
    try:
        # Set up Chrome Options
        chrome_options = Options()
        chrome_options.add_argument('--headless')
        chrome_options.add_argument('--disable-gpu')

        # Set up WebDriver
        driver = webdriver.Chrome(CHROME_DRIVER_PATH, options=chrome_options)

        # Navigate to URL and take screenshot
        driver.get(url)
        screenshot = driver.get_screenshot_as_png()

        # Close WebDriver
        driver.quit()

        return BytesIO(screenshot)

    except Exception as e:
        print(f"Error taking screenshot: {e}")
        return None

def upload_to_s3(bucket_name, object_key, data):
    try:
        s3 = boto3.client('s3', aws_access_key_id=AWS_ACCESS_KEY_ID,
                          aws_secret_access_key=AWS_SECRET_ACCESS_KEY)
        s3.put_object(Body=data, Bucket=bucket_name, Key=object_key)

        return True

    except NoCredentialsError:
        print("Credentials not available")
        return False
    except Exception as e:
        print(f"Error uploading to S3: {e}")
        return False

def handle_request(url):
    if is_allowed_destination(url):
        screenshot = get_screenshot(url)
        if screenshot:
            object_key = f"screenshots/{url}.png"
            upload_to_s3(BUCKET_NAME, object_key, screenshot.getvalue())
            return {"success": True, "message": "Screenshot uploaded successfully"}
        else:
            return {"success": False, "message": "Error taking screenshot"}

    else:
        return {"success": False, "message": "Destination not allowed"}

if __name__ == "__main__":
    url = 'https://example.com'
    result = handle_request(url)
    print(result)